map "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/SleepQualityQuestionnaireResponseToObservation" = "SleepQualityQuestionnaireResponseToObservation"

/// url = "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/SleepQualityQuestionnaireResponseToObservation"
/// name = "SleepQualityQuestionnaireResponseToObservation"
/// title = "Sleep Quality Q to O"
/// status = "active"

uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QR as source
uses "http://hl7.org/fhir/StructureDefinition/Observation" alias Obs as target

imports "http://hl7.org/fhir/StructureMap/*"
imports "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/QuestionnaireResponseToObservationBase"

group SleepQualityQuestionnaireResponseToObservation(source src : QR, target tgt : Obs) {
  src then SetObservationBase(src, tgt) "Base";
  src -> tgt.meta = create('Meta') as meta,
    meta.profile = 'https://fhir.hl7.at/prenudge/appdata/r4/StructureDefinition/at-prenudge-sleep-quality-observation' "SetProfile";
  src -> tgt.code = cc('http://loinc.org', '61987-4', 'Sleep quality') "SetCode";
  // effectiveDateTime from authored timestamp (questionnaire completion time)
  src.authored as authored -> tgt.effectiveDateTime = create('dateTime') as dt,
    dt.value = authored "SetEffective";
  src.item as item where linkId = 'Q16' then MapSleepQuality(item, tgt) "ProcessQ16";
}

group MapSleepQuality(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    // Extract Q16 valueCoding as CodeableConcept
    answer.valueCoding as coding -> tgt.value = create('CodeableConcept') as cc,
      cc.coding = coding "SetSleepQualityValue";

    // TODO: Note mapping disabled due to MaLaC-HD limitation
    // Annotation.text (markdown) target not supported with FHIR string source
    // See: https://gitlab.com/cdehealth/malac-hd/-/issues/128

    // Map comment to note
    // answer.item as commentItem where linkId = 'comment' then {
    //   commentItem.answer as commentAnswer then {
    //     commentAnswer.value as commentText -> tgt.note as note,
    //       note.text = commentText "SetNoteText";
    //   } "ProcessCommentAnswer";
    // } "ProcessComment";

  } "ProcessAnswer";
}
